const items = $input.all();

let pendientes = 0;
let solucionados = 0;
const total = items.length;

if (total === 0) {
  return { total: 0, pendientes: 0, solucionados: 0, ultimo: {} };
}

for (const item of items) {
  const estado = item.json.estado?.toString().trim();

  if (estado === 'Pendiente') {
    pendientes++;
  } else if (estado === 'Solucionado') {
    solucionados++;
  }
}

const ultimoDato = items[total - 1].json;

return {
  total,
  pendientes,
  solucionados,
  ultimo: ultimoDato
};
